let outs = [null, null, null, null, null, null, null];

// SEPARAÇÃO POR TÓPICO
if (msg.topic.includes("byte10")) { outs[0] = msg; } //Memórias gerais
if (msg.topic.includes("byte11")) { outs[1] = msg; } //Memorias gerais
if (msg.topic.includes("byte15")) { outs[2] = msg; } //Quantidade de peças metálicas
if (msg.topic.includes("byte20")) { outs[3] = msg; } //Quantidade de peças pretas
if (msg.topic.includes("byte25")) { outs[4] = msg; } //Quantidade de peças vermelhas
if (msg.topic.includes("byte50")) { outs[5] = msg; } //Tempo da peça na linha
if (msg.topic.includes("byte40")) { outs[6] = msg; } //Tempo de start

return outs;

let valorByte = Number(msg.payload);

// Extração dos bits
let bit0 = (valorByte & 1) !== 0;
let bit1 = (valorByte & 2) !== 0;
let bit2 = (valorByte & 4) !== 0; // RESET
let bit3 = (valorByte & 8) !== 0;
let bit4 = (valorByte & 16) !== 0; // Ocupada (Linha com peça)
let bit5 = (valorByte & 32) !== 0; // Metálica
let bit6 = (valorByte & 64) !== 0; // Vermelha
let bit7 = (valorByte & 128) !== 0; // Preta

// Busca a memória de cor e tempos
let memoria = context.get('memoriaCor') || 'vazio';
let anteriorOcupada = context.get('ocupadaAnterior') || false;
let horaEntrada = context.get('horaEntrada') || 0;
let msgAnalise = null;

// ==========================================
// LÓGICA DE TEMPO POR PEÇA (NOVO!)
// ==========================================
// Detecta quando a peça ACABA DE CHEGAR (bit 4 subiu)
if (bit4 === true && anteriorOcupada === false) {
    context.set('horaEntrada', Date.now());
}

// Detecta quando a peça ACABA DE SAIR (bit 4 desceu)
if (bit4 === false && anteriorOcupada === true) {
    let agora = Date.now();
    let duracao = (agora - horaEntrada) / 1000; // converte ms para segundos

    // Prepara o pacote para o nó de médias
    msgAnalise = {
        payload: duracao,
        cor: memoria,
        topic: "nova_peca"
    };
}
// Salva o estado atual para comparar no próximo ciclo
context.set('ocupadaAnterior', bit4);

// ==========================================
// ESTADO DO CRONÔMETRO E RESET
// ==========================================
flow.set("resetAtivo", bit2);

if (bit0 === true) {
    flow.set("estadoDaMaquina", "START");
} else if (bit1 === true) {
    flow.set("estadoDaMaquina", "STOP");
}

if (bit2 === true) {
    flow.set("tempoStart", 0);
    flow.set("tempoStop", 0);
    flow.set("estadoDaMaquina", "STOP");
}

// ==========================================
// LÓGICA DE MEMÓRIA DE COR
// ==========================================
if (bit4 === false) {
    memoria = 'vazio';
    context.set('memoriaCor', memoria);
} else {
    if (memoria === 'vazio') memoria = 'preta';
    if (memoria !== 'metalica') {
        if (bit5 === true) memoria = 'metalica';
        else if (bit6 === true) memoria = 'vermelha';
        else if (bit7 === true) memoria = 'preta';
    }
    context.set('memoriaCor', memoria);
}

// Sinais de botões (preparando saídas 1 a 8)
let m_start = bit0 ? { payload: true, topic: "start" } : null;
let m_stop = bit1 ? { payload: true, topic: "stop" } : null;
let m_reset = bit2 ? { payload: true, topic: "reset" } : null;
let m_problema = bit3 ? { payload: true, topic: "problema" } : null;
let m_ocupada = { payload: bit4 };
let m_metalica = (memoria === 'metalica' && bit4) ? { payload: true, topic: "metalica" } : null;
let m_vermelha = (memoria === 'vermelha' && bit4) ? { payload: true, topic: "vermelha" } : null;
let m_preta = (memoria === 'preta' && bit4) ? { payload: true, topic: "preta" } : null;

// Retorna 9 saídas. A nona (msgAnalise) só terá dados quando a peça sair!
return [m_start, m_stop, m_reset, m_problema, m_ocupada, m_metalica, m_vermelha, m_preta, msgAnalise];

let valorByte = Number(msg.payload);

//-----------------------------------//
// EXTRAÇÃO DOS BITS
//-----------------------------------//
let bit0 = (valorByte & 1) !== 0; 
let bit1 = (valorByte & 2) !== 0; 
let bit2 = (valorByte & 4) !== 0; 
let bit3 = (valorByte & 8) !== 0; 
let bit4 = (valorByte & 16) !== 0;
let bit5 = (valorByte & 32) !== 0; // EMERGÊNCIA
let bit6 = (valorByte & 64) !== 0;
let bit7 = (valorByte & 128) !== 0; // SENSOR METÁLICO

//-----------------------------------//
// BLOQUEIO DO CRONÔMETRO
//-----------------------------------//
// Aqui avisamos ao cronômetro: "Para tudo!"
flow.set("emergenciaAtiva", bit5);

//-----------------------------------//
// PREPARAÇÃO DAS SAÍDAS
//-----------------------------------//
let m_bit0 = { payload: bit0 };
let m_bit1 = { payload: bit1 };
let m_bit2 = { payload: bit2 };
let m_bit3 = { payload: bit3 };
let m_bit4 = { payload: bit4 };
let m_emergencia = { payload: bit5, topic: "emergencia" };
let m_bit6 = { payload: bit6 };

// Adicionado o tópico para o painel reconhecer a cor/material
let m_bit7 = { payload: bit7, topic: "bit7" }; 

return [m_bit0, m_bit1, m_bit2, m_bit3, m_bit4, m_emergencia, m_bit6, m_bit7];

// 0. Verifica se o Broker está conectado antes de processar qualquer coisa
let brokerLigado = flow.get("brokerLigado");

if (brokerLigado === false) {
    // Se a conexão caiu, ele para a execução aqui e não soma nada nos tempos
    return null; 
}

// 1. Puxa os estados de bloqueio
let emergencia = flow.get("emergenciaAtiva") || false;
let resetAtivo = flow.get("resetAtivo") || false;

// 2. Pega os tempos atuais
let tempoStart = flow.get("tempoStart") || 0;
let tempoStop = flow.get("tempoStop") || 0;
let tempoTotal = tempoStart + tempoStop;

// 3. CÁLCULO PARA O GAUGE (Análise de Disponibilidade)
// Calculamos a porcentagem: (Tempo Start / Tempo Total) * 100
let disponibilidade = 0;
if (tempoTotal > 0) {
    disponibilidade = (tempoStart / tempoTotal) * 100;
}

// 4. Função para formatar HH:MM:SS
function format(s) {
    let h = Math.floor(s / 3600).toString().padStart(2, '0');
    let m = Math.floor((s % 3600) / 60).toString().padStart(2, '0');
    let s_ = (s % 60).toString().padStart(2, '0');
    return `${h}:${m}:${s_}`;
}

// =============================================================
// LÓGICA DE CONGELAMENTO (Emergência ou Reset)
// =============================================================
if (emergencia === true || resetAtivo === true) {
    return [
        { payload: format(tempoStart) },
        { payload: format(tempoStop) },
        { payload: format(tempoTotal) },
        { payload: Number(disponibilidade.toFixed(1)) } // Gauge parado
    ];
}

// 5. Se estiver tudo OK, conta o tempo normalmente
let estado = flow.get("estadoDaMaquina") || "STOP";

if (estado === "START") {
    tempoStart++;
} else {
    tempoStop++;
}

// Salva os novos tempos na memória
flow.set("tempoStart", tempoStart);
flow.set("tempoStop", tempoStop);

// Recalcula o total e a disponibilidade com o novo segundo somado
tempoTotal = tempoStart + tempoStop;
disponibilidade = (tempoStart / tempoTotal) * 100;

// 6. RETORNO DAS 4 SAÍDAS
return [
    { payload: format(tempoStart) },                 // Saída 1 (Texto)
    { payload: format(tempoStop) },                  // Saída 2 (Texto)
    { payload: format(tempoTotal) },                 // Saída 3 (Texto)
    { payload: Number(disponibilidade.toFixed(1)) }  // Saída 4 (Número para o Gauge)
];

// 1. Puxa a contagem atual salva na memória deste nó (ou zera se for a primeira vez)
let stats = context.get('contagens') || { vermelhas: 0, pretas: 0, metal: 0 };

// 2. Atualiza o valor correspondente dependendo de qual tópico chegou
if (msg.topic) {
    let valor = Number(msg.payload) || 0;

    if (msg.topic.includes("byte25")) {
        stats.vermelhas = valor;
    } 
    else if (msg.topic.includes("byte20")) {
        stats.pretas = valor;
    } 
    else if (msg.topic.includes("byte15")) {
        stats.metal = valor;
    } 
    else {
        // Se chegar alguma mensagem que não seja dessas 3, ele ignora
        return null;
    }
}

// 3. Salva a contagem atualizada na memória do nó
context.set('contagens', stats);

// 4. Monta as fatias do Gráfico Donut
// O 'topic' será o nome que aparece na legenda, e o 'payload' é a quantidade atual
let msgVermelha = { topic: "Vermelhas", payload: stats.vermelhas };
let msgPreta    = { topic: "Pretas",    payload: stats.pretas };
let msgMetal    = { topic: "Metálica",  payload: stats.metal };

// 5. Envia as três mensagens para a mesma saída (Saída 1)
// Os colchetes duplos [[ ]] disparam as 3 fatias de uma vez para atualizar o gráfico
return [[msgVermelha, msgPreta, msgMetal]];

// 1. Inicializa ou recupera os acumuladores do contexto
let stats = context.get('stats') || {
    total: { soma: 0, conta: 0 },
    vermelha: { soma: 0, conta: 0 },
    preta: { soma: 0, conta: 0 },
    metalica: { soma: 0, conta: 0 }
};

// 2. Processa a nova peça se o tópico for correto
if (msg.payload && msg.topic === "nova_peca") {
    let duracao = Number(msg.payload); // Garante que a leitura é número
    let cor = msg.cor;

    stats.total.soma += duracao;
    stats.total.conta++;

    if (stats[cor]) {
        stats[cor].soma += duracao;
        stats[cor].conta++;
    }
    context.set('stats', stats);
}

// 3. Função para calcular as médias
function calcMedia(tipo) {
    return stats[tipo].conta > 0 ? (stats[tipo].soma / stats[tipo].conta) : 0;
}

// --- PREPARAÇÃO DA VARIÁVEL ---
let mediaTotalNum = calcMedia('total');

// --- MENSAGEM 1: GRÁFICO DE BARRAS ---
let msgGrafico = {
    payload: [{
        "series": ["Tempo Médio (s)"],
        "data": [[
            Number(mediaTotalNum.toFixed(2)),
            Number(calcMedia('vermelha').toFixed(2)),
            Number(calcMedia('preta').toFixed(2)),
            Number(calcMedia('metalica').toFixed(2))
        ]],
        "labels": ["Total", "Vermelha", "Preta", "Metálica"]
    }]
};

// --- MENSAGEM 2: GAUGE (VALOR MÉDIO SIMPLES) ---
// Removemos os controles de máximo e cores dinâmicas que dependiam do timeout
let msgGauge = {
    payload: Number(mediaTotalNum.toFixed(2))
};

// Retorna para as 2 saídas do nó Function (Lembre-se de mudar no nó para 2 saídas)
return [msgGrafico, msgGauge];

// 0. Verifica se o botão foi realmente pressionado.
// Ignora o evento se a mensagem for de "soltar" o botão (false ou 0)
if (msg.payload === false || msg.payload === 0 || msg.payload === "0") {
    return null;
}

// 1. Mapeamento de entrada para o tópico MQTT correspondente (alerta removido)
const mapeamento = {
    "start_nr": "sorting_fms/start",
    "stop_nr": "sorting_fms/stop",
    "reset_nr": "sorting_fms/reset"
};

const topicosDisponiveis = [
    "sorting_fms/start",
    "sorting_fms/stop",
    "sorting_fms/reset"
];

const topicoAtivo = mapeamento[msg.topic];

if (topicoAtivo) {
    // PASSO 1: Manda 0 apenas para os OUTROS tópicos (Zera o resto)
    topicosDisponiveis.forEach(t => {
        if (t !== topicoAtivo) {
            node.send({ topic: t, payload: 0 });
        }
    });

    // PASSO 2: Manda 1 (inteiro) apenas para o botão apertado
    node.send({ topic: topicoAtivo, payload: 1 });

    // PASSO 3: Após 500ms, "solta" o botão ativo (volta para 0)
    setTimeout(() => {
        node.send({ topic: topicoAtivo, payload: 0 });
    }, 500);
}

return null;

// 1. Zera as variáveis na memória do fluxo
flow.set("tempoStart", 0);
flow.set("tempoStop", 0);

// 2. Opcional: Enviar uma mensagem para limpar os displays imediatamente
// Retornamos 0 formatado para as saídas de texto e 0 para o gauge
function zerado() { return "00:00:00"; }

return [
    { payload: zerado() }, // Saída 1: Tempo Start
    { payload: zerado() }, // Saída 2: Tempo Stop
    { payload: zerado() }, // Saída 3: Tempo Total
    { payload: 0 }         // Saída 4: Gauge de Disponibilidade
];

// O nó Status envia msg.status, mas nós queremos trabalhar com msg.payload
// Vamos extrair o texto do status com segurança
let statusTexto = "";

if (msg.status && msg.status.text) {
    statusTexto = msg.status.text;
} else {
    // Caso o nó seja disparado sem texto definido ainda
    return null;
}

let layout = {
    text: "BROKER DESCONECTADO",
    color: "#d32f2f" // Vermelho padrão
};

// Se o texto contiver 'connected' ou 'conectado'
if (statusTexto.indexOf("connected") !== -1 || statusTexto.indexOf("conectado") !== -1) {
    layout.text = "BROKER CONECTADO";
    layout.color = "#2e7d32"; // Verde
    flow.set("brokerLigado", true);
} else {
    flow.set("brokerLigado", false);
}

// AGORA SIM definimos o payload para o resto do fluxo
msg.payload = layout;

return msg;

// 1. Lemos o valor do bit5 que chegou do separador
let sinalRecebido = msg.payload; // Pode ser true ou false

// --- AJUSTE DE LÓGICA (NORMALMENTE FECHADO / NORMALMENTE ABERTO) ---
// Se o seu botão de emergência for Normalmente Fechado (NF), ele manda 'false' quando pressionado.
// Se esse for o caso, mude a variável abaixo para true. Se for um botão comum (NA), deixe false.
let botaoNormalmenteFechado = true; 

// Descobre se estamos de fato em emergência
let isEmergencia = botaoNormalmenteFechado ? (sinalRecebido === false) : (sinalRecebido === true);

// 2. Montamos o HTML da emergência
let telaEmergencia = `
<style>
    @keyframes pulse-emergency {
        0%   { background-color: #FDE992; }
        50%  { background-color: #ff0000; color: white; }
        100% { background-color: #FDE992; }
    }
    .emergency-box {
        padding: 25px;
        border-radius: 12px;
        text-align: center;
        font-weight: 900;
        font-size: 22px;
        border: 5px dashed #000;
        color: #ff0000;
        animation: pulse-emergency 1.2s infinite ease-in-out;
    }
</style>
<div class="emergency-box">
     EMERGÊNCIA DE LINHA PRESSIONADA 🚨<br>
    <small style="font-size: 14px; display: block; margin-top: 10px; color: #000;">O RESET DEVE SER FEITO MANUALMENTE</small>
</div>
`;

// 3. Montamos o HTML de quando NÃO há emergência (pode ser vazio para sumir do painel)
let telaNormal = `<div style="display: none;"></div>`; // Um bloco invisível para limpar a tela

// 4. Decide qual tela enviar baseado no status da emergência
let telaAtual = isEmergencia ? telaEmergencia : telaNormal;

// 5. Lemos o último estado salvo na memória para evitar recarregar a tela à toa
let ultimoEstado = context.get("ultimoEstado");

// Se a tela atual já for a que está no painel, encerra por aqui
if (ultimoEstado === telaAtual) {
    return null;
}

// 6. Atualizamos a memória e enviamos a nova tela
context.set("ultimoEstado", telaAtual);
msg.payload = telaAtual;

return msg;

// 1. Verificamos se a entrada é REALMENTE uma emergência
// Se o payload for falso (0), limpamos o estado e não exibimos a tela
if (msg.payload === false || msg.payload === 0) {
    context.set("ultimoEstado", null); 
    return null; 
}

// 2. Se chegou aqui, a emergência é verdadeira. Montamos o HTML:
let telaEmergencia = `
<style>
    @keyframes pulse-emergency {
        0%   { background-color: #FDE992; }
        50%  { background-color: #ff0000; color: white; }
        100% { background-color: #FDE992; }
    }
    .emergency-box {
        padding: 25px;
        border-radius: 12px;
        text-align: center;
        font-weight: 900;
        font-size: 22px;
        border: 5px dashed #000;
        color: #ff0000;
        animation: pulse-emergency 1.2s infinite ease-in-out;
    }
</style>
<div class="emergency-box">
     EMERGÊNCIA DE LINHA PRESSIONADA 🚨<br>
    <small style="font-size: 14px; display: block; margin-top: 10px; color: #000;">O RESET DEVE SER FEITO MANUALMENTE</small>
</div>
`;

// 3. Trava de repetição: Só envia se o estado anterior não era emergência
let ultimoEstado = context.get("ultimoEstado");

if (ultimoEstado === "EMERGENCIA_ATIVA") {
    return null; // Já está exibindo, não faz nada
}

// 4. Ativa a emergência na memória e envia
context.set("ultimoEstado", "EMERGENCIA_ATIVA");
msg.payload = telaEmergencia;

return msg;

// === 1. LÓGICA DO BOTÃO LIMPAR ===
// Intercepta a palavra exata enviada pelo botão
if (msg.payload === "limpar" || msg.topic === "limpar_log") {
    context.set('logs_producao', []); // Apaga a memória interna do Node-RED
    msg.payload = [];                 // Envia uma lista vazia para apagar o ecrã
    return msg;
}

// === 2. CONFIGURAÇÕES NORMAIS ===
const MAX_LOGS = 15;

let logs = context.get('logs_producao') || [];
let ultimosValores = context.get('ultimos_valores') || {};

let topico = String(msg.topic || "");
let valor = Number(msg.payload);

// Removido o código 49
const codigosDeErro = [3, 4, 5, 99];

// Se não houve mudança geral no valor do tópico, ignora
if (ultimosValores[topico] === valor) {
    return null;
}

let valorAntigo = ultimosValores[topico] || 0;
ultimosValores[topico] = valor;
context.set('ultimos_valores', ultimosValores);

let tipo = "";
let mensagem = "";
let cor = "";
let data = new Date();
let horaFormatada = data.toLocaleTimeString('pt-BR');

// === 3. LÓGICA DE EVENTOS ===

if (topico.includes("byte15") && valor > valorAntigo) {
    tipo = "Metálica";
    mensagem = `Peça detetada. Total: ${valor}`;
    cor = "#95a5a6";
}
else if (topico.includes("byte20") && valor > valorAntigo) {
    tipo = "Preta";
    mensagem = `Peça detetada. Total: ${valor}`;
    cor = "#2c3e50";
}
else if (topico.includes("byte25") && valor > valorAntigo) {
    tipo = "Vermelha";
    mensagem = `Peça detetada. Total: ${valor}`;
    cor = "#e74c3c";
}

// === LÓGICA DE MÁQUINA CORRIGIDA (START / STOP / ERROS) ===
else if (topico.includes("byte10") || topico.includes("byte11")) {

    // Extrai o estado exato dos bits de controle atuais e antigos
    let startAtual = (valor & 1) !== 0;
    let startAntigo = (valorAntigo & 1) !== 0;

    let stopAtual = (valor & 2) !== 0;
    let stopAntigo = (valorAntigo & 2) !== 0;

    // Só registra se o botão START foi ativado AGORA (mudou de 0 para 1)
    if (startAtual === true && startAntigo === false) {
        tipo = "START";
        mensagem = "Máquina em operação.";
        cor = "#27ae60";
    }
    // Só registra se o botão STOP foi ativado AGORA (mudou de 0 para 1)
    else if (stopAtual === true && stopAntigo === false) {
        tipo = "STOP";
        mensagem = "Máquina parada.";
        cor = "#e67e22";
    }
    // Verifica códigos de erro numéricos normais
    else if (codigosDeErro.includes(valor)) {
        tipo = "ALERTA";
        mensagem = "Falha/Aviso na máquina! Código: " + valor;
        cor = "#c0392b";
    }
    // Verifica reset do código de erro
    else if (valor === 0 && codigosDeErro.includes(valorAntigo)) {
        tipo = "Status";
        mensagem = "Máquina normalizada / resetada.";
        cor = "#2ecc71";
    }
    else {
        return null; // Ignora as outras mudanças (como a peça entrando e saindo)
    }
}
else {
    return null;
}

// Monta e guarda o registro
let novoLog = { hora: horaFormatada, tipo: tipo, mensagem: mensagem, cor: cor };
logs.unshift(novoLog);
if (logs.length > MAX_LOGS) { logs.pop(); }

context.set('logs_producao', logs);
msg.payload = logs;
return msg;

// Recupera o estado atual salvo na memória (contexto do nó)
// Se não existir, cria o estado inicial "AGUARDANDO"
let estado = context.get("estadoAtual") || {
    texto: "AGUARDANDO...",
    cor: "#2c3e50",
    icone: "power-off",
    emergencia: false
};

let topic = msg.topic || "";
let payload = msg.payload; // true ou false

// 1. TRATAMENTO DA EMERGÊNCIA (Você confirmou que false = Sem emergência)
if (topic.includes("emergencia")) {
    estado.emergencia = (payload === true || payload === 1 || payload === "1");
}

// 2. TRATAMENTO DOS OUTROS STATUS (Só aceita se a emergência NÃO estiver ativa)
if (!estado.emergencia) {

    // Só mudamos o status se o botão correspondente for pressionado (true)
    if (payload === true || payload === 1 || payload === "1") {

        if (topic.includes("start")) {
            estado.texto = "RODANDO";
            estado.cor = "#2ecc71";
            estado.icone = "play-circle";
        } 
        else if (topic.includes("stop") || topic.includes("reset")) {
            estado.texto = "INTERROMPIDO";
            estado.cor = "#e67e22";
            estado.icone = topic.includes("reset") ? "refresh" : "stop-circle";
        } 
        else if (topic.includes("problema")) {
            estado.texto = "ERRO / FALHA";
            estado.cor = "#c0392b";
            estado.icone = "warning";
        }
    }
} else {
    // Se a emergência estiver ativa, força o visual de alerta
    estado.texto = "EMERGÊNCIA ATIVA";
    estado.cor = "#c0392b";
    estado.icone = "exclamation-triangle";
}

// Salva o estado para a próxima vez que uma mensagem chegar
context.set("estadoAtual", estado);

// Coloca os dados organizados dentro de msg.statusInfo
msg.statusInfo = estado;

return msg;

// ==========================================
// NÓ FUNCTION: ANALISADOR DE PEÇA SEGURO
// ==========================================
let contagens = context.get("contagens") || { metal: -1, preta: -1, vermelha: -1 };
let topico = String(msg.topic || "").toLowerCase();

// Força a conversão para número (útil caso o CLP envie como string ou buffer)
let valor = Number(msg.payload); 
let msgTela = null;

// --- DEBUG VISUAL NO NODE-RED ---
// Isso vai mostrar embaixo do nó qual tópico e valor ele está lendo AGORA!
node.status({fill:"blue", shape:"dot", text: "Lendo: " + topico + " | Val: " + valor});

// Evita processar sinais booleanos (true/false) acidentais que não sejam números de contagem
if (!isNaN(valor)) {

    // ==========================================
    // ANÁLISE DE CONTAGEM (A Prova Final)
    // ==========================================
    // METAL (Byte 15)
    if (topico.includes("byte15")) {
        // Se for a primeira vez lendo e o valor for > 0, OU se o contador subiu
        if ((contagens.metal === -1 && valor > 0) || (contagens.metal !== -1 && valor > contagens.metal)) {
            msgTela = { payload: "metalica" };
        }
        contagens.metal = valor;
    } 

    // VERMELHA (Byte 25)
    else if (topico.includes("byte25")) {
        if ((contagens.vermelha === -1 && valor > 0) || (contagens.vermelha !== -1 && valor > contagens.vermelha)) {
            msgTela = { payload: "vermelha" };
        }
        contagens.vermelha = valor;
    }

    // PRETA (Byte 20)
    else if (topico.includes("byte20")) {
        if ((contagens.preta === -1 && valor > 0) || (contagens.preta !== -1 && valor > contagens.preta)) {
            msgTela = { payload: "preta" };
        }
        contagens.preta = valor;
    }
}

// Salva as contagens na memória para o próximo ciclo
context.set("contagens", contagens);

// Se detectou uma peça nova, envia para a tela e muda o status visual para VERDE
if (msgTela) {
    node.status({fill:"green", shape:"dot", text: "Enviou para tela: " + msgTela.payload});
    return msgTela;
}

// Não retorna nada se a contagem não subiu (não polui a tela)
return null;

// Recupera a memória interna do Node-RED ou cria uma zerada
let contagens = context.get("memoriaContagens") || { vermelhas: 0, pretas: 0, metal: 0 };
let topico = String(msg.topic || "");
let valor = Number(msg.payload) || 0;

// Atualiza apenas a cor correspondente
if (topico.includes("byte25")) {
    contagens.vermelhas = valor;
} else if (topico.includes("byte20")) {
    contagens.pretas = valor;
} else if (topico.includes("byte15")) {
    contagens.metal = valor;
}

// Calcula o total
contagens.total = contagens.vermelhas + contagens.pretas + contagens.metal;

// Salva a memória para a próxima vez
context.set("memoriaContagens", contagens);

// Envia o pacote completo para a tela
msg.payload = contagens;
return msg;
